/**
 * PageHeader — spec §10.1, §11
 *
 * h4 title, optional caption (subtitle), optional right-aligned action.
 * One per page; renders the page's primary heading and optional context.
 */
import * as React from 'react';
import { Box, Stack, Typography } from '@mui/material';
import { semanticColors } from '@/constants/ThemeConstants';

export interface PageHeaderProps {
    /** Page title — rendered as <h1> for landmark semantics. */
    title: React.ReactNode;
    /** Optional subtitle / caption beneath the title. */
    subtitle?: React.ReactNode;
    /** Optional right-aligned action (button, icon button, chip group). */
    action?: React.ReactNode;
    /** When true, renders title in a smaller variant (h5) — for nested pages. */
    dense?: boolean;
}

export const PageHeader: React.FC<PageHeaderProps> = ({
    title,
    subtitle,
    action,
    dense = false,
}) => (
    <Box
        component="header"
        sx={{
            display: 'flex',
            alignItems: { xs: 'flex-start', sm: 'center' },
            justifyContent: 'space-between',
            gap: 2,
            flexDirection: { xs: 'column', sm: 'row' },
        }}
    >
        <Stack spacing={0.5} sx={{ minWidth: 0, flex: 1 }}>
            <Typography
                component="h1"
                variant={dense ? 'h5' : 'h4'}
                sx={{
                    color: semanticColors.text.primary,
                    fontWeight: 600,
                    lineHeight: 1.25,
                    overflowWrap: 'anywhere',
                }}
            >
                {title}
            </Typography>
            {subtitle && (
                <Typography
                    variant="body2"
                    sx={{ color: semanticColors.text.secondary }}
                >
                    {subtitle}
                </Typography>
            )}
        </Stack>
        {action && (
            <Box sx={{ flexShrink: 0, alignSelf: { xs: 'stretch', sm: 'center' } }}>
                {action}
            </Box>
        )}
    </Box>
);

export default PageHeader;
